import {Composition} from 'remotion';
import {VideoWithSubtitles} from './VideoWithSubtitles';

export const RemotionRoot: React.FC = () => {
  return (
    <>
      <Composition
        id="VideoWithSubtitles"
        component={VideoWithSubtitles}
        durationInFrames={1500}  // 50秒 * 30fps
        fps={30}
        width={1080}   // 9:16 竖屏
        height={1920}
        defaultProps={{}}
      />
    </>
  );
};

import {useVideoConfig, useCurrentFrame, Audio, staticFile} from 'remotion';
import {useState, useEffect} from 'react';

// 字幕数据（从 SRT 解析）
const subtitles = [
  {start: 0.1, end: 3.9, text: "你是不是每天晚上都把手机充到100%才睡？"},
  {start: 3.9, end: 9.7, text: "告诉你一个反常识的真相：这样做，其实正在慢慢毁掉你的电池。"},
  {start: 9.7, end: 14.4, text: "锂电池最怕的，就是长期处于满电或空电状态。"},
  {start: 14.4, end: 21.6, text: "苹果和安卓官方都承认：电池维持在20%到80%之间，寿命最长。"},
  {start: 21.6, end: 23.4, text: "充到100%？"},
  {start: 23.4, end: 27.8, text: "高压状态会让电池喘不过气。"},
  {start: 27.8, end: 31.2, text: "用到0%自动关机？"},
  {start: 31.2, end: 36.9, text: "深度放电直接损伤电芯。"},
  {start: 36.9, end: 39.0, text: "那该怎么办？"},
  {start: 39.0, end: 42.2, text: "其实很简单：随用随充，别等红格。"},
  {start: 42.2, end: 49.9, text: "睡前充到80%就够了，现在的快充，早上刷个牙就能补满。"},
  {start: 49.9, end: 55.0, text: "你现在充电习惯是哪种？"},
  {start: 55.0, end: 60.0, text: "评论区告诉我，是随用随充党，还是必须100%才安心？"},
];

export const VideoWithSubtitles: React.FC = () => {
  const {fps, durationInFrames} = useVideoConfig();
  const frame = useCurrentFrame();
  const currentTime = frame / fps;

  // 淡入动画
  const opacity = Math.min(1, frame / 15);

  // 找到当前应该显示的字幕
  const currentSubtitle = subtitles.find(
    sub => currentTime >= sub.start && currentTime <= sub.end
  );

  return (
    <div
      style={{
        width: 1080,
        height: 1920,
        background: 'linear-gradient(135deg, #1a1a2e 0%, #16213e 50%, #0f3460 100%)',
        display: 'flex',
        flexDirection: 'column',
        justifyContent: 'center',
        alignItems: 'center',
        position: 'relative',
        opacity,
      }}
    >
      {/* 背景装饰 */}
      <div
        style={{
          position: 'absolute',
          top: 100,
          right: 50,
          width: 200,
          height: 200,
          borderRadius: '50%',
          background: 'rgba(233, 69, 96, 0.1)',
        }}
      />
      <div
        style={{
          position: 'absolute',
          bottom: 200,
          left: 50,
          width: 300,
          height: 300,
          borderRadius: '50%',
          background: 'rgba(79, 172, 254, 0.08)',
        }}
      />

      {/* 主标题区 */}
      <div
        style={{
          position: 'absolute',
          top: 150,
          textAlign: 'center',
          padding: '0 60px',
        }}
      >
        <div
          style={{
            fontSize: 48,
            color: '#e94560',
            fontWeight: 'bold',
            marginBottom: 20,
            fontFamily: 'Noto Sans CJK SC, sans-serif',
          }}
        >
          ⚡ 充电真相
        </div>
        <div
          style={{
            fontSize: 32,
            color: '#888',
            fontFamily: 'Noto Sans CJK SC, sans-serif',
          }}
        >
          你的电池正在被你"充满"毁掉
        </div>
      </div>

      {/* 电池图标动画 */}
      <div
        style={{
          position: 'absolute',
          top: 450,
          display: 'flex',
          flexDirection: 'column',
          alignItems: 'center',
        }}
      >
        <div
          style={{
            width: 200,
            height: 360,
            border: '8px solid #fff',
            borderRadius: 30,
            position: 'relative',
            display: 'flex',
            flexDirection: 'column',
            justifyContent: 'flex-end',
            overflow: 'hidden',
          }}
        >
          {/* 电池头 */}
          <div
            style={{
              position: 'absolute',
              top: -30,
              left: '50%',
              transform: 'translateX(-50%)',
              width: 80,
              height: 20,
              background: '#fff',
              borderRadius: '10px 10px 0 0',
            }}
          />
          {/* 电量填充 - 动态变化 */}
          <div
            style={{
              width: '100%',
              height: currentTime < 10 ? '100%' : currentTime < 25 ? '60%' : '80%',
              background: currentTime < 10 
                ? 'linear-gradient(180deg, #ff6b6b 0%, #ee5a6f 100%)' 
                : 'linear-gradient(180deg, #4facfe 0%, #00f2fe 100%)',
              transition: 'all 0.5s ease',
            }}
          />
          {/* 百分比文字 */}
          <div
            style={{
              position: 'absolute',
              top: '50%',
              left: '50%',
              transform: 'translate(-50%, -50%)',
              fontSize: 48,
              fontWeight: 'bold',
              color: '#fff',
              fontFamily: 'Noto Sans CJK SC, sans-serif',
              textShadow: '0 2px 10px rgba(0,0,0,0.5)',
            }}
          >
            {currentTime < 10 ? '100%' : currentTime < 25 ? '60%' : '80%'}
          </div>
        </div>
      </div>

      {/* 字幕区域 */}
      <div
        style={{
          position: 'absolute',
          bottom: 300,
          left: 60,
          right: 60,
          minHeight: 200,
          display: 'flex',
          justifyContent: 'center',
          alignItems: 'center',
          textAlign: 'center',
        }}
      >
        {currentSubtitle && (
          <div
            style={{
              fontSize: 52,
              color: '#fff',
              fontWeight: 'bold',
              lineHeight: 1.5,
              fontFamily: 'Noto Sans CJK SC, sans-serif',
              textShadow: '0 4px 20px rgba(0,0,0,0.5)',
              padding: '20px 40px',
              background: 'rgba(0,0,0,0.3)',
              borderRadius: 20,
            }}
          >
            {currentSubtitle.text}
          </div>
        )}
      </div>

      {/* 底部提示 */}
      <div
        style={{
          position: 'absolute',
          bottom: 100,
          fontSize: 28,
          color: '#666',
          fontFamily: 'Noto Sans CJK SC, sans-serif',
        }}
      >
        双击屏幕 + 关注，获取更多冷知识
      </div>

      {/* 音频 */}
      <Audio src={staticFile('voice.mp3')} />
    </div>
  );
};

